insert into public.lessons (id, module_id, title, content, duration_minutes, order_index) values

('l10301', 'm103', 'Text, Headings & Paragraphs', E'# Text, Headings & Paragraphs\n\n## Why This Topic Matters\nText is the primary content on the web. Structuring it correctly with the right HTML elements improves readability, SEO, and accessibility.\n\n## Learning Objectives\n- Use all six heading levels correctly\n- Mark up paragraphs, quotes, and preformatted text\n- Use inline text elements for emphasis and meaning\n- Understand the difference between presentational and semantic markup\n\n## Core Concepts\n\n### Headings — h1 to h6\n```html\n<h1>Page Title (only one per page)</h1>\n<h2>Major Section</h2>\n<h3>Subsection</h3>\n<h4>Sub-subsection</h4>\n<h5>Rarely used</h5>\n<h6>Smallest heading</h6>\n```\n\n### Paragraphs & Line Breaks\n```html\n<p>A paragraph of text. Browsers add margin automatically.</p>\n<p>Another paragraph.</p>\n\n<!-- Line break inside a paragraph -->\n<p>Line one<br>Line two</p>\n\n<!-- Horizontal rule (thematic break) -->\n<hr>\n```\n\n### Inline Text Elements\n```html\n<strong>Bold — strong importance</strong>\n<em>Italic — emphasis</em>\n<mark>Highlighted text</mark>\n<del>Deleted text</del>\n<ins>Inserted text</ins>\n<sub>Subscript H<sub>2</sub>O</sub>\n<sup>Superpower x<sup>2</sup></sup>\n<code>inline code</code>\n<kbd>Ctrl+C</kbd>\n<abbr title="HyperText Markup Language">HTML</abbr>\n<cite>Book Title</cite>\n<q>Short inline quotation</q>\n```\n\n### Block Quotations & Preformatted\n```html\n<blockquote cite="https://source.com">\n  <p>The web does not just connect machines, it connects people.</p>\n  <footer>— Tim Berners-Lee</footer>\n</blockquote>\n\n<pre><code>\nfunction hello() {\n  console.log("Hello!");\n}\n</code></pre>\n```\n\n## Best Practices\n- Use headings in order — never skip from h1 to h4\n- One h1 per page (the main topic)\n- Use `<strong>` not `<b>` for importance; `<em>` not `<i>` for stress\n- Use `<p>` for paragraphs, not `<br><br>`\n\n## Common Mistakes\n- Using headings for styling (big text) instead of document structure\n- Multiple h1 elements on one page\n- Using `<b>` and `<i>` (presentational) instead of semantic equivalents\n\n## Interview Questions\n1. What is the difference between `<strong>` and `<b>`?\n2. How many `<h1>` elements should a page have?\n3. What is the `<abbr>` element used for?\n\n## Assignment\nMark up a recipe page: use h1 for the dish name, h2 for Ingredients and Instructions sections, h3 for sub-steps, paragraphs for descriptions, and appropriate inline elements for important terms.', 20, 1),

('l10401', 'm104', 'Links, Images & Media', E'# Links, Images & Media\n\n## Why This Topic Matters\nLinks and images are the most-used HTML elements after text. Getting their attributes right affects navigation, SEO, performance, and accessibility.\n\n## Learning Objectives\n- Create internal, external, and anchor links\n- Embed images with proper alt text\n- Use srcset for responsive images\n- Embed audio and video natively\n\n## Core Concepts\n\n### The Anchor Element\n```html\n<!-- External link -->\n<a href="https://example.com" target="_blank" rel="noopener noreferrer">Visit Example</a>\n\n<!-- Internal link -->\n<a href="/about">About Us</a>\n\n<!-- Same-page anchor -->\n<a href="#contact">Jump to Contact</a>\n<section id="contact">...</section>\n\n<!-- Email & phone links -->\n<a href="mailto:hello@example.com">Email Us</a>\n<a href="tel:+911234567890">Call Us</a>\n\n<!-- Download link -->\n<a href="/resume.pdf" download>Download Resume</a>\n```\n\n### Images\n```html\n<!-- Basic image -->\n<img src="photo.jpg" alt="A developer working at a desk" width="800" height="600">\n\n<!-- Lazy loading -->\n<img src="hero.jpg" alt="Hero image" loading="lazy">\n\n<!-- Responsive images with srcset -->\n<img\n  src="photo-800.jpg"\n  srcset="photo-400.jpg 400w, photo-800.jpg 800w, photo-1200.jpg 1200w"\n  sizes="(max-width: 600px) 400px, 800px"\n  alt="Responsive photo"\n>\n\n<!-- Figure with caption -->\n<figure>\n  <img src="chart.png" alt="Q3 sales increased by 30%">\n  <figcaption>Q3 2024 Sales Chart</figcaption>\n</figure>\n```\n\n### Audio & Video\n```html\n<audio controls>\n  <source src="podcast.mp3" type="audio/mpeg">\n  <source src="podcast.ogg" type="audio/ogg">\n  Your browser does not support audio.\n</audio>\n\n<video controls width="720" poster="thumbnail.jpg">\n  <source src="lesson.mp4" type="video/mp4">\n  <source src="lesson.webm" type="video/webm">\n  <track kind="subtitles" src="captions.vtt" srclang="en" label="English">\n  Your browser does not support video.\n</video>\n```\n\n## Best Practices\n- Always add descriptive `alt` text to images (empty `alt=""` for decorative images)\n- Use `rel="noopener noreferrer"` on external `target="_blank"` links\n- Add `width` and `height` to images to prevent layout shift (CLS)\n- Use `loading="lazy"` for below-fold images\n\n## Common Mistakes\n- Missing alt text (accessibility failure)\n- No rel="noopener" on _blank links (security risk)\n- Using images for text (bad for SEO and accessibility)\n\n## Interview Questions\n1. Why is alt text important on images?\n2. What is the purpose of rel="noopener noreferrer"?\n3. What is the srcset attribute used for?\n\n## Assignment\nBuild a photo gallery page: 6 images with proper alt text, responsive srcset, lazy loading on non-hero images, each wrapped in a figure with figcaption. Add a "View Full Size" link on each image.', 25, 1),

('l10501', 'm105', 'Lists & Tables', E'# Lists & Tables\n\n## Why This Topic Matters\nLists structure related items; tables present tabular data. Using the right one in the right context improves readability and accessibility.\n\n## Learning Objectives\n- Create ordered, unordered, and definition lists\n- Build accessible HTML tables\n- Know when to use tables vs CSS layouts\n- Use table headings and scope for accessibility\n\n## Core Concepts\n\n### Unordered List\n```html\n<ul>\n  <li>HTML</li>\n  <li>CSS</li>\n  <li>JavaScript\n    <ul><!-- Nested list -->\n      <li>React</li>\n      <li>Vue</li>\n    </ul>\n  </li>\n</ul>\n```\n\n### Ordered List\n```html\n<ol start="1" type="1">\n  <li>Install Node.js</li>\n  <li>Create project: <code>npm init</code></li>\n  <li>Install dependencies</li>\n</ol>\n\n<!-- Reversed list -->\n<ol reversed>\n  <li>Step 3</li>\n  <li>Step 2</li>\n  <li>Step 1</li>\n</ol>\n```\n\n### Definition List\n```html\n<dl>\n  <dt>HTML</dt>\n  <dd>HyperText Markup Language — structure of the web</dd>\n  <dt>CSS</dt>\n  <dd>Cascading Style Sheets — presentation of the web</dd>\n</dl>\n```\n\n### Tables\n```html\n<table>\n  <caption>Monthly Sales Data</caption>\n  <thead>\n    <tr>\n      <th scope="col">Month</th>\n      <th scope="col">Revenue</th>\n      <th scope="col">Orders</th>\n    </tr>\n  </thead>\n  <tbody>\n    <tr>\n      <th scope="row">January</th>\n      <td>$12,000</td>\n      <td>240</td>\n    </tr>\n    <tr>\n      <th scope="row">February</th>\n      <td>$15,500</td>\n      <td>310</td>\n    </tr>\n  </tbody>\n  <tfoot>\n    <tr>\n      <th scope="row">Total</th>\n      <td>$27,500</td>\n      <td>550</td>\n    </tr>\n  </tfoot>\n</table>\n```\n\n### Spanning Cells\n```html\n<td colspan="2">Spans two columns</td>\n<td rowspan="3">Spans three rows</td>\n```\n\n## Best Practices\n- Use `<caption>` to describe table purpose\n- Use `scope="col"` on column headers, `scope="row"` on row headers\n- Use `<thead>`, `<tbody>`, `<tfoot>` to structure tables\n- Never use tables for page layout — use CSS Grid/Flexbox\n\n## Common Mistakes\n- Using tables for page layout (breaks responsive design and accessibility)\n- Missing `scope` attribute on `<th>` (screen readers cannot determine header relationship)\n- Forgetting `<thead>` and `<tbody>` (browsers still render but structure is lost)\n\n## Interview Questions\n1. When should you use a table vs a list?\n2. What is the `scope` attribute on `<th>`?\n3. What is the difference between `<th>` and `<td>`?\n\n## Assignment\nCreate a course schedule table with days of the week as columns and time slots as rows. Use colspan for lunch break. Add caption, thead, tbody. Make it screen-reader accessible with scope attributes.', 25, 1),

('l10801', 'm108', 'Web Accessibility & ARIA', E'# Web Accessibility & ARIA\n\n## Why This Topic Matters\nOver 1 billion people have disabilities. Accessible websites are not just legally required in many countries — they are better for everyone.\n\n## Learning Objectives\n- Understand WCAG guidelines\n- Write keyboard-navigable HTML\n- Use ARIA roles and attributes correctly\n- Test pages for accessibility\n\n## Core Concepts\n\n### WCAG Principles (POUR)\n| Principle | Meaning |\n|---|---|\n| Perceivable | Content can be seen/heard |\n| Operable | Works with keyboard and assistive tech |\n| Understandable | Clear language and predictable behavior |\n| Robust | Works with current and future assistive tech |\n\n### Keyboard Navigation\n```html\n<!-- All interactive elements must be keyboard-focusable -->\n<a href="/page">Link</a>          <!-- naturally focusable -->\n<button>Button</button>           <!-- naturally focusable -->\n<input type="text">               <!-- naturally focusable -->\n\n<!-- Custom interactive elements need tabindex -->\n<div role="button" tabindex="0" onkeydown="handleKey(event)">\n  Click or press Enter\n</div>\n\n<!-- Remove from tab order -->\n<div tabindex="-1">Not tabbable but focusable by JS</div>\n```\n\n### ARIA Roles & Attributes\n```html\n<!-- Landmark roles (often redundant with semantic HTML) -->\n<div role="navigation" aria-label="Main menu">\n<div role="main">\n<div role="complementary">\n\n<!-- Labels for form elements -->\n<label for="search">Search</label>\n<input id="search" type="text" aria-describedby="search-hint">\n<p id="search-hint">Enter a course name or keyword</p>\n\n<!-- Live regions (screen reader announcements) -->\n<div aria-live="polite" aria-atomic="true">\n  <!-- Dynamic content changes announced to screen readers -->\n</div>\n\n<!-- Expandable components -->\n<button aria-expanded="false" aria-controls="menu-list">\n  Menu\n</button>\n<ul id="menu-list" hidden>...</ul>\n\n<!-- Images -->\n<img src="logo.png" alt="R-Learn logo">   <!-- informative -->\n<img src="divider.png" alt="">             <!-- decorative -->\n```\n\n### Focus Management\n```javascript\n// Move focus after modal opens\ndocument.getElementById("modal-close").focus();\n\n// Trap focus inside modal\nmodal.addEventListener("keydown", (e) => {\n  if (e.key === "Tab") {\n    // Cycle focus within modal\n  }\n});\n```\n\n### Color & Contrast\n- Normal text: contrast ratio ≥ 4.5:1\n- Large text (18pt+): ratio ≥ 3:1\n- Never convey information by color alone\n\n## Best Practices\n- Write semantic HTML first — ARIA is a last resort\n- Test with keyboard only (no mouse)\n- Test with a screen reader (NVDA, VoiceOver)\n- Use a contrast checker tool\n\n## Common Mistakes\n- Adding ARIA to semantic elements that already have the role\n- `aria-label` on elements that have visible text (use aria-labelledby instead)\n- Hiding focusable elements with `display:none` in JS that should be keyboard-accessible\n\n## Interview Questions\n1. What does ARIA stand for and when should you use it?\n2. What is the difference between `aria-label` and `aria-labelledby`?\n3. What WCAG level does your project target?\n\n## Assignment\nBuild an accessible accordion: three expandable sections. Must work with keyboard (Enter/Space to toggle), use aria-expanded, aria-controls, and aria-hidden correctly.', 30, 1),

('l10901', 'm109', 'SEO Fundamentals', E'# SEO Fundamentals\n\n## Why This Topic Matters\nSearch engines drive the majority of web traffic. Writing SEO-aware HTML is a developer responsibility — not just a marketer concern.\n\n## Learning Objectives\n- Write semantic HTML that improves SEO\n- Use meta tags correctly\n- Understand structured data (JSON-LD)\n- Know Core Web Vitals basics\n\n## Core Concepts\n\n### Essential Meta Tags\n```html\n<head>\n  <meta charset="UTF-8">\n  <meta name="viewport" content="width=device-width, initial-scale=1.0">\n  <meta name="description" content="Learn web development with R-Learn. 14 tracks, 155+ lessons.">\n  <meta name="robots" content="index, follow">\n\n  <!-- Open Graph (Facebook, LinkedIn sharing) -->\n  <meta property="og:title" content="R-Learn Platform">\n  <meta property="og:description" content="Professional web development courses">\n  <meta property="og:image" content="https://rlearn.com/og-image.jpg">\n  <meta property="og:url" content="https://rlearn.com">\n\n  <!-- Twitter Card -->\n  <meta name="twitter:card" content="summary_large_image">\n  <meta name="twitter:title" content="R-Learn Platform">\n\n  <title>R-Learn — Professional Web Development Courses</title>\n\n  <!-- Canonical URL (prevents duplicate content) -->\n  <link rel="canonical" href="https://rlearn.com/courses">\n</head>\n```\n\n### Structured Data (JSON-LD)\n```html\n<script type="application/ld+json">\n{\n  "@context": "https://schema.org",\n  "@type": "Course",\n  "name": "JavaScript ES6+",\n  "description": "Complete modern JavaScript course",\n  "provider": {\n    "@type": "Organization",\n    "name": "R-Learn"\n  },\n  "educationalLevel": "Intermediate"\n}\n</script>\n```\n\n### SEO-Friendly HTML Patterns\n```html\n<!-- Good heading hierarchy for SEO -->\n<h1>JavaScript ES6+ Complete Guide</h1>  <!-- One per page -->\n<h2>Variables and Scope</h2>\n<h2>Functions and Closures</h2>\n<h3>Arrow Functions</h3>\n\n<!-- Descriptive link text (not "click here") -->\n<a href="/courses/javascript">View JavaScript Course</a>\n\n<!-- Image alt text helps image SEO -->\n<img src="js-cheatsheet.png" alt="JavaScript ES6 Cheatsheet — arrow functions, destructuring, spread">\n\n<!-- Semantic regions help crawlers understand structure -->\n<main>  <!-- Primary content -->\n<nav>   <!-- Navigation (may be crawled differently) -->\n<article> <!-- Independent content pieces -->\n```\n\n### Core Web Vitals\n| Metric | Measures | Target |\n|---|---|---|\n| LCP | Largest Contentful Paint (load speed) | < 2.5s |\n| FID/INP | Interaction delay | < 200ms |\n| CLS | Cumulative Layout Shift | < 0.1 |\n\n## Best Practices\n- Title tag: 50-60 characters, unique per page\n- Meta description: 150-160 characters, compelling\n- One h1 per page, meaningful text\n- Descriptive URLs: `/courses/javascript` not `/page?id=3`\n\n## Common Mistakes\n- Duplicate title tags across pages\n- Missing or generic meta descriptions\n- Vague link text like "click here" or "read more"\n- Content inside JavaScript only (hard for crawlers)\n\n## Interview Questions\n1. What is a canonical URL and why do you need it?\n2. What is the difference between `index` and `noindex` robots meta?\n3. How does semantic HTML help SEO?\n\n## Assignment\nAudit a page using Lighthouse in Chrome DevTools. Fix all SEO warnings: missing meta description, non-descriptive link text, missing alt text. Screenshot before and after scores.', 25, 1),

('l11001', 'm110', 'Audio, Video & Canvas', E'# Audio, Video & Canvas\n\n## Why This Topic Matters\nRich media — audio players, video courses, interactive diagrams — are core features of modern learning platforms.\n\n## Learning Objectives\n- Embed audio and video with full browser support\n- Control media with the HTMLMediaElement API\n- Draw on `<canvas>` programmatically\n- Understand media accessibility\n\n## Core Concepts\n\n### Video Element\n```html\n<video\n  id="course-video"\n  controls\n  width="100%"\n  poster="thumbnail.jpg"\n  preload="metadata"\n>\n  <source src="lesson.mp4" type="video/mp4">\n  <source src="lesson.webm" type="video/webm">\n  <track kind="subtitles" src="en.vtt" srclang="en" label="English" default>\n  <track kind="subtitles" src="hi.vtt" srclang="hi" label="Hindi">\n  <p>Your browser does not support video. <a href="lesson.mp4">Download it</a>.</p>\n</video>\n```\n\n### JavaScript Media API\n```javascript\nconst video = document.getElementById("course-video");\n\n// Playback control\nvideo.play();\nvideo.pause();\nvideo.currentTime = 30;  // Seek to 30 seconds\nvideo.playbackRate = 1.5; // 1.5x speed\nvideo.volume = 0.8;        // 80% volume\nvideo.muted = true;\n\n// Events\nvideo.addEventListener("play", () => console.log("Playing"));\nvideo.addEventListener("ended", () => markLessonComplete());\nvideo.addEventListener("timeupdate", () => {\n  const progress = (video.currentTime / video.duration) * 100;\n  progressBar.style.width = `${progress}%`;\n});\n\n// Fullscreen\nvideo.requestFullscreen();\n```\n\n### Audio Element\n```html\n<audio controls preload="none">\n  <source src="podcast.mp3" type="audio/mpeg">\n  <source src="podcast.ogg" type="audio/ogg">\n</audio>\n```\n\n### Canvas — Drawing API\n```html\n<canvas id="chart" width="600" height="400"></canvas>\n\n<script>\nconst canvas = document.getElementById("chart");\nconst ctx = canvas.getContext("2d");\n\n// Draw shapes\nctx.fillStyle = "#3b82f6";\nctx.fillRect(50, 50, 200, 100);  // x, y, width, height\n\n// Draw text\nctx.font = "20px Inter";\nctx.fillStyle = "#111";\nctx.fillText("Progress", 60, 180);\n\n// Draw circle\nctx.beginPath();\nctx.arc(300, 200, 80, 0, Math.PI * 2);\nctx.fillStyle = "#10b981";\nctx.fill();\n\n// Draw line\nctx.beginPath();\nctx.moveTo(0, 0);\nctx.lineTo(600, 400);\nctx.strokeStyle = "#ef4444";\nctx.lineWidth = 2;\nctx.stroke();\n</script>\n```\n\n## Best Practices\n- Always provide multiple source formats (mp4 + webm)\n- Add `<track>` subtitles for accessibility\n- Use `poster` to show thumbnail before play\n- Use `preload="metadata"` to load duration without loading media\n\n## Common Mistakes\n- Missing subtitle tracks (accessibility requirement)\n- Autoplay with sound (blocked by browsers and bad UX)\n- Canvas without fallback content\n\n## Interview Questions\n1. What is the `<track>` element used for?\n2. How do you detect when a video ends?\n3. What is the difference between `<canvas>` and SVG?\n\n## Assignment\nBuild a custom video player: play/pause button, seek bar, volume control, and a progress tracker that saves the current timestamp to localStorage so users can resume.', 30, 1),

('l11101', 'm111', 'SVG & Web Graphics', E'# SVG & Web Graphics\n\n## Why This Topic Matters\nSVG (Scalable Vector Graphics) renders icons and illustrations perfectly at any size. It is used for logos, charts, icons, and animations in every modern web app.\n\n## Learning Objectives\n- Write inline SVG in HTML\n- Use basic SVG shapes and paths\n- Animate SVG with CSS\n- Understand SVG vs Canvas use cases\n\n## Core Concepts\n\n### Inline SVG\n```html\n<svg width="200" height="200" viewBox="0 0 200 200" xmlns="http://www.w3.org/2000/svg">\n  <!-- Rectangle -->\n  <rect x="10" y="10" width="80" height="80" fill="#3b82f6" rx="8"/>\n\n  <!-- Circle -->\n  <circle cx="150" cy="50" r="40" fill="#10b981" opacity="0.8"/>\n\n  <!-- Line -->\n  <line x1="10" y1="150" x2="190" y2="150" stroke="#ef4444" stroke-width="3"/>\n\n  <!-- Text -->\n  <text x="50" y="180" font-family="Inter" font-size="16" fill="#111">SVG!</text>\n\n  <!-- Path (complex shapes) -->\n  <path d="M10 100 Q100 10 190 100" fill="none" stroke="#8b5cf6" stroke-width="2"/>\n</svg>\n```\n\n### SVG Icons (common pattern)\n```html\n<!-- Reusable icon system with symbols -->\n<svg style="display:none">\n  <symbol id="icon-check" viewBox="0 0 24 24">\n    <path d="M20 6L9 17l-5-5" stroke="currentColor" stroke-width="2"\n      fill="none" stroke-linecap="round"/>\n  </symbol>\n  <symbol id="icon-close" viewBox="0 0 24 24">\n    <path d="M18 6L6 18M6 6l12 12" stroke="currentColor" stroke-width="2"\n      stroke-linecap="round"/>\n  </symbol>\n</svg>\n\n<!-- Use anywhere -->\n<svg width="24" height="24" aria-hidden="true">\n  <use href="#icon-check"/>\n</svg>\n```\n\n### CSS Animations on SVG\n```css\n/* Animate an SVG circle to pulse */\n.pulse-circle {\n  animation: pulse 2s ease-in-out infinite;\n}\n\n@keyframes pulse {\n  0%, 100% { transform: scale(1); opacity: 1; }\n  50% { transform: scale(1.2); opacity: 0.7; }\n}\n\n/* SVG stroke animation (draw-on effect) */\n.path-draw {\n  stroke-dasharray: 300;\n  stroke-dashoffset: 300;\n  animation: draw 2s ease forwards;\n}\n\n@keyframes draw {\n  to { stroke-dashoffset: 0; }\n}\n```\n\n### SVG vs Canvas\n| Feature | SVG | Canvas |\n|---|---|---|\n| Type | Vector (scalable) | Raster (pixel-based) |\n| DOM | Yes (manipulatable) | No |\n| Best for | Icons, charts, illustrations | Games, image processing |\n| Accessibility | Built-in (ARIA) | Manual |\n| Performance at scale | Slower with many elements | Better for many elements |\n\n## Best Practices\n- Inline SVG for dynamic/animated icons\n- External SVG files for static images\n- Add `aria-label` or `<title>` for accessibility\n- Use `currentColor` so SVG icons inherit CSS color\n\n## Common Mistakes\n- Missing viewBox (SVG does not scale properly)\n- No accessible label on meaningful SVGs\n- Using raster images where SVG would look sharper\n\n## Interview Questions\n1. What is the viewBox attribute in SVG?\n2. When would you use Canvas instead of SVG?\n3. How do you make SVG icons change color based on CSS?\n\n## Assignment\nCreate a progress dashboard with an SVG circular progress ring that animates from 0% to a target value using CSS stroke-dashoffset animation.', 25, 1),

('l11201', 'm112', 'HTML Performance & Best Practices', E'# HTML Performance & Best Practices\n\n## Why This Topic Matters\nFast pages rank higher, convert better, and retain users. HTML structure directly affects how quickly browsers can parse and render your page.\n\n## Learning Objectives\n- Understand the critical rendering path\n- Optimize resource loading order\n- Use modern loading attributes\n- Apply HTML best practices for production\n\n## Core Concepts\n\n### Critical Rendering Path\n```\nHTML Parse → DOM\nCSS Parse  → CSSOM\nDOM + CSSOM → Render Tree → Layout → Paint\n```\nAnything blocking this path delays First Contentful Paint (FCP).\n\n### Resource Loading Strategies\n```html\n<head>\n  <!-- Preconnect to third-party origins -->\n  <link rel="preconnect" href="https://fonts.googleapis.com">\n\n  <!-- Preload critical resources -->\n  <link rel="preload" href="hero.jpg" as="image">\n  <link rel="preload" href="main.css" as="style">\n\n  <!-- CSS in head — render blocking, but necessary -->\n  <link rel="stylesheet" href="main.css">\n\n  <!-- Non-critical CSS deferred -->\n  <link rel="stylesheet" href="print.css" media="print">\n</head>\n\n<body>\n  <!-- Content first -->\n\n  <!-- Scripts at bottom -->\n  <script src="app.js" defer></script>    <!-- Defer: load async, run after HTML -->\n  <script src="analytics.js" async></script> <!-- Async: load and run ASAP -->\n</body>\n```\n\n### Image Optimization\n```html\n<!-- Specify dimensions to avoid CLS -->\n<img src="hero.jpg" width="1200" height="600" alt="Hero">\n\n<!-- Use modern formats with fallback -->\n<picture>\n  <source srcset="hero.avif" type="image/avif">\n  <source srcset="hero.webp" type="image/webp">\n  <img src="hero.jpg" alt="Hero image" width="1200" height="600">\n</picture>\n\n<!-- Lazy load below-fold images -->\n<img src="photo.jpg" loading="lazy" decoding="async" alt="Photo">\n\n<!-- Eagerly load LCP image -->\n<img src="hero.jpg" loading="eager" fetchpriority="high" alt="Hero">\n```\n\n### HTML Production Checklist\n```\n[ ] Valid HTML (W3C validator)\n[ ] One h1 per page\n[ ] All images have alt text\n[ ] All inputs have labels\n[ ] lang attribute on html element\n[ ] Meta description and title\n[ ] Viewport meta tag\n[ ] Favicon\n[ ] No inline styles (use CSS)\n[ ] No deprecated elements (center, font, etc.)\n[ ] Semantic structure\n```\n\n## Best Practices\n- Place critical CSS inline or preload it\n- Use `defer` on all non-critical scripts\n- Specify image dimensions to prevent layout shift\n- Minify HTML in production\n\n## Common Mistakes\n- Render-blocking scripts in `<head>` without async/defer\n- No width/height on images (causes CLS)\n- Loading all fonts eagerly\n- Not using picture element for modern image formats\n\n## Interview Questions\n1. What is the difference between `defer` and `async` on a script tag?\n2. What causes Cumulative Layout Shift (CLS)?\n3. What does `rel="preload"` do?\n\n## Assignment\nRun a Lighthouse audit on your HTML project. Achieve a Performance score of 80+. Document 3 optimizations you made and the score improvement each produced.', 25, 1)

